func solve(n int64) string {
	// Calculate n squared and n cubed
	n2 := n * n
	n3 := n * n * n

	// Convert n2 to hexadecimal (base 16)
	hexStr := fmt.Sprintf("%x", n2)
	hexStr = strings.ToUpper(hexStr)

	// Convert n3 to base 36
	// Base 36 digits go from 0-9 and A-Z (0-35)
	// So we need to map numbers 10-35 to letters A-Z
	trihexStr := fmt.Sprintf("%d", n3)
	for i := 0; i < len(trihexStr); i++ {
		digit := trihexStr[i] - '0'
		if digit >= 10 {
			trihexStr = trihexStr[:i] + string('A'+digit-10) + trihexStr[i+1:]
		}
	}

	return hexStr + trihexStr
}
